
    CREATE TABLE IF NOT EXISTS sigmap_benchmarks (
        repo_id SERIAL PRIMARY KEY,
        repo_name VARCHAR(255) UNIQUE NOT NULL,
        github_url VARCHAR(512),
        primary_language VARCHAR(50),
        file_count INTEGER,
        loc_estimate INTEGER,
        monorepo_flag BOOLEAN DEFAULT FALSE,
        monorepo_module_count INTEGER DEFAULT 0,
        raw_tokens_estimate INTEGER,
        final_tokens INTEGER,
        reduction_percent DECIMAL(5,2),
        tokens_per_file DECIMAL(10,2),
        compression_ratio DECIMAL(10,2),
        benchmark_time_ms INTEGER,
        analyze_time_ms INTEGER,
        report_time_ms INTEGER,
        health_time_ms INTEGER,
        analyze_slow_time_ms INTEGER,
        total_time_ms INTEGER,
        health_score INTEGER,
        success_flag BOOLEAN DEFAULT TRUE,
        error_code VARCHAR(100),
        validation_status VARCHAR(50),
        timeout_flag BOOLEAN DEFAULT FALSE,
        benchmark_date DATE,
        sigmap_version VARCHAR(20),
        benchmark_mode_count INTEGER,
        data_completeness_percent INTEGER,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );

    CREATE INDEX idx_language ON sigmap_benchmarks(primary_language);
    CREATE INDEX idx_reduction ON sigmap_benchmarks(reduction_percent);
    CREATE INDEX idx_tokens ON sigmap_benchmarks(final_tokens);
    
